const fs = require("fs");
const path = require("path");

const iconsDir = path.resolve(__dirname, "../src/icons");
const registryPath = path.resolve(__dirname, "../src/registry.ts");

let files = [];
try {
  files = fs
    .readdirSync(iconsDir)
    .filter((f) => f.endsWith(".json"))
    .sort();
} catch {
  // icons directory does not exist yet
}

const imports = files
  .map((f) => {
    const name = f.replace(/\.json$/, "");
    return `  "${name}": () => import("./icons/${f}"),`;
  })
  .join("\n");

const content = [
  "// This file is auto-generated by scripts/generate-registry.js",
  "// Do not edit manually — changes will be overwritten.",
  "export const registry = {",
  imports,
  "} as const;",
  "export type IconId = keyof typeof registry;",
  "",
].join("\n");

fs.writeFileSync(registryPath, content, "utf-8");
console.log(`Regenerated registry at ${registryPath}`);
